const fs = require('fs');
function writeFile(filePath, data, options, callback) {
  if (typeof options === 'function') { callback = options; options = {}; }
  try { fs.writeFileSync(filePath, data, options); if (callback) callback(null); }
  catch (e) { if (callback) callback(e); }
}
function writeFileSync(filePath, data, options) { fs.writeFileSync(filePath, data, options); }
module.exports = { writeFile, writeFileSync };
